// Get original form data
const form = $('New Submission Received').first().json;

// Clean Gemini output
let text = $json.output;
text = text.replace(/```json/g, '');
text = text.replace(/```/g, '');
text = text.trim();

const classification = JSON.parse(text);

return [{
  json: {
    // Original form fields
    full_name: form['Full Name'],
    email: form['Email Address'],
    company: form['Company Name'],
    company_size: form['Company Size'],
    industry: form['Industry'],
    budget: form['Monthly Budget'],
    message: form['What do you need help with?'],
    urgency: form['How urgent is this for you?'],

    // AI Classification result
    client_type: classification.client_type || 'SME',
    confidence: classification.confidence || 'MEDIUM',
    classification_reason: classification.reason || 'Unable to classify'
  }
}];

// Get all previous data
const client = $('Parse Client Type').first().json;

// Get email content from AI Email Generator
let emailText = $('AI Email Generator').first().json.output;
emailText = emailText.replace(/```json/g, '');
emailText = emailText.replace(/```/g, '');
emailText = emailText.trim();
const emailContent = JSON.parse(emailText);

// Clean next action decision
let actionText = $json.output;
actionText = actionText.replace(/```json/g, '');
actionText = actionText.replace(/```/g, '');
actionText = actionText.trim();
const action = JSON.parse(actionText);

return [{
  json: {
    // Client profile
    full_name: client.full_name,
    email: client.email,
    company: client.company,
    industry: client.industry,
    budget: client.budget,
    message: client.message,
    urgency: client.urgency,

    // AI Decision 1 — Classification
    client_type: client.client_type,
    confidence: client.confidence,
    classification_reason: client.classification_reason,

    // AI Decision 2 — Email content
    email_subject: emailContent.subject || 'Welcome to the agency',
    email_body: emailContent.body || 'Thank you for reaching out.',

    // AI Decision 3 — Next action
    next_action: action.next_action || 'ADD_TO_NEWSLETTER',
    urgency_level: action.urgency_level || 'MEDIUM',
    action_reason: action.reason || 'Standard follow-up'
  }
}];

